        }
    }

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;
        timeout_detected = false;

        /* Apply control policy based on temperature */
        if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* TEMP < 47: turn heater on */
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        } else if (input.temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* TEMP > 52: turn heater off */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_SAFE_OFF;
        } else if (input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && input.temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* 50 <= TEMP <= 52: check if rising */
            if (controller->last_temperature_c > 0 && input.temperature_c > controller->last_temperature_c) {
                /* Temperature is rising: turn heater off early, count as HOLDING */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                /* Not rising: hold previous safe actuator state */
                /* State remains as-is, heater_on preserved from previous state */
                if (controller->state == CONTROLLER_STATE_HEATING) {
                    /* Keep heating if we were already heating */
                } else if (controller->state == CONTROLLER_STATE_HOLDING) {
                    /* Hold whatever state we had */
                } else {
                    controller->state = CONTROLLER_STATE_HOLDING;
                }
            }
        } else {
            /* 47 <= TEMP < 50: hold the previous safe actuator state */
            if (controller->state != CONTROLLER_STATE_HEATING && controller->heater_on) {
                controller->state = CONTROLLER_STATE_HOLDING;
            } else if (!controller->heater_on) {
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* Check for timeout condition */
        if (timeout_detected) {
            controller->has_valid_sensor = false;
            controller_set_safe_off(controller);
            output.timed_out = true;
        } else {
            /* No new frame but not yet timed out: hold previous state */
            if (controller->state == CONTROLLER_STATE_HEATING && controller->heater_on) {
                /* Continue heating */
            } else if (controller->state == CONTROLLER_STATE_HOLDING) {
                /* Hold current state */
            } else {
                /* SAFE_OFF or no valid sensor: stay safe off */
                controller_set_safe_off(controller);
            }
        }
        break;
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}
